+import { $internal } from '../common';
+import type { Trait } from '../trait/types';
+
+let aspectId = 0;
+
+export type Aspect<TTraits extends readonly Trait[] = readonly Trait[]> = {
+    readonly id: number;
+    readonly traits: TTraits;
+    readonly schema: Record<string, unknown>;
+    readonly fieldTraits: ReadonlyMap<string, Trait>;
+} & ((params?: Record<string, unknown>) => [Aspect<TTraits>, Record<string, unknown>]);
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!value && typeof value === 'function' && 'traits' in value && 'fieldTraits' in value;
+}
+
+export function createAspect<const TInputs extends readonly (Trait | Aspect)[]>(
+    ...inputs: TInputs
+): Aspect<readonly Trait[]> {
+    if (inputs.length < 2) throw new Error('createAspect requires at least two traits');
+
+    const traits: Trait[] = [];
+    for (const input of inputs) {
+        if (isAspect(input)) traits.push(...input.traits);
+        else traits.push(input);
+    }
+
+    const fieldTraits = new Map<string, Trait>();
+    for (const trait of traits) {
+        if (trait[$internal].relation) throw new Error('Relations cannot be constituents of an aspect');
+        if (traits.indexOf(trait) !== traits.lastIndexOf(trait)) {
+            throw new Error('An aspect cannot contain the same trait more than once');
+        }
+        if (typeof trait.schema === 'function') {
+            throw new Error('AoS traits cannot be constituents of an aspect');
+        }
+        for (const field of Object.keys(trait.schema)) {
+            if (fieldTraits.has(field)) {
+                throw new Error(`Aspect constituents have an overlapping field name: ${field}`);
+            }
+            fieldTraits.set(field, trait);
+        }
+    }
+
+    const schema = Object.fromEntries(
+        traits.flatMap((trait) => Object.entries(trait.schema as Record<string, unknown>))
+    );
+    const aspect = Object.assign((params: Record<string, unknown> = {}) => [aspect, params] as const, {
+        id: aspectId++,
+        traits: Object.freeze(traits),
+        schema: Object.freeze(schema),
+        fieldTraits,
+    }) as Aspect;
+    return Object.freeze(aspect);
+}
