+        if (isAspect(param)) return [getAspect(world, entity, param)];
+        if (isModifier(param)) {
+            if (param.type === 'not') return [];
+            return param.traits.filter((trait) => trait[$internal].type !== 'tag').map((trait) => getTrait(world, entity, trait));
+        }
+        if (isRelationPair(param)) return [];
+        const trait = param as Trait;
+        return trait[$internal].type === 'tag' ? [] : [getTrait(world, entity, trait)];
+    });
+    const commit = (entity: Entity, state: any[]) => {
+        let index = 0;
+        for (const param of params) {
+            if (isAspect(param)) setAspect(world, entity, param, state[index++] ?? {});
+            else if (isModifier(param)) {
+                if (param.type === 'not') continue;
+                for (const trait of param.traits) if (trait[$internal].type !== 'tag') setTrait(world, entity, trait, state[index++]);
+            } else if (!isRelationPair(param) && (param as Trait)[$internal].type !== 'tag') {
+                setTrait(world, entity, param as Trait, state[index++]);
+            }
+        }
+    };
+    const results = Object.assign(entities, {
+        readEach(callback: any) {
+            entities.forEach((entity, index) => callback(stateFor(entity), entity, index));
+            return results;
+        },
+        updateEach(callback: any) {
+            entities.forEach((entity, index) => {
+                const state = stateFor(entity);
+                callback(state, entity, index);
+                if (world.has(entity)) commit(entity, state);
+            });
+            return results;
+        },
+        useStores: () => results,
+        select: () => results,
